  1→// ABOUTME: Dashboard client — fetches session data, renders UI, handles interactions.
  2→// ABOUTME: Vanilla JS with no build step; polls /api/sessions for updates.
  3→
  4→(function () {
  5→  "use strict";
  6→
  7→  // --- State ---
  8→  let dashboardData = null;
  9→  let lastScannedTime = null;
 10→  let expandedRepos = new Set(); // repo_root values that are expanded
 11→  var timeFilterDays = Infinity; // max days back to show (Infinity = all)
 12→
 13→  // --- DOM refs ---
 14→  const $loading = document.getElementById("loading");
 15→  const $repoGroups = document.getElementById("repo-groups");
 16→  const $nonRepoGroups = document.getElementById("non-repo-groups");
 17→  const $chronoView = document.getElementById("chrono-view");
 18→  const $emptyState = document.getElementById("empty-state");
 19→  const $lastScan = document.getElementById("last-scan");
 20→  const $btnRefresh = document.getElementById("btn-refresh");
 21→  const $scanDays = document.getElementById("scan-days");
 22→  const $timeSlider = document.getElementById("time-slider");
 23→  const $timeSliderLabel = document.getElementById("time-slider-label");
 24→  const $searchOverlay = document.getElementById("search-overlay");
 25→  const $searchInput = document.getElementById("search-input");
 26→  const $searchResults = document.getElementById("search-results");
 27→
 28→  // --- Helpers ---
 29→
 30→  function timeAgo(isoString) {
 31→    if (!isoString) return "--";
 32→    const diff = Date.now() - new Date(isoString).getTime();
 33→    const seconds = Math.floor(diff / 1000);
 34→    if (seconds < 60) return seconds + "s ago";
 35→    const minutes = Math.floor(seconds / 60);
 36→    if (minutes < 60) return minutes + "m ago";
 37→    const hours = Math.floor(minutes / 60);
 38→    if (hours < 24) return hours + "h ago";
 39→    const days = Math.floor(hours / 24);
 40→    return days + "d ago";
 41→  }
 42→
 43→  function statusCssClass(status) {
 44→    return (status || "").replace(/\s+/g, "-");
 45→  }
 46→
 47→  function isActiveDot(status) {
 48→    return ["in progress", "likely in progress", "waiting for input"].includes(status);
 49→  }
 50→
 51→  var INITIAL_VISIBLE = 10;
 52→
 53→  function escapeHtml(str) {
 54→    const div = document.createElement("div");
 55→    div.textContent = str || "";
 56→    return div.innerHTML;
 57→  }
 58→
 59→  function sessionLabel(session) {
 60→    if (session.summary) return session.summary;
 61→    if (session.slug) return session.slug;
 62→    return session.id.substring(0, 8) + "\u2026";
 63→  }
 64→
 65→  function allSessions() {
 66→    if (!dashboardData) return [];
 67→    var sessions = [];
 68→    (dashboardData.repo_groups || []).forEach(function (g) {
 69→      g.sessions.forEach(function (s) {
 70→        sessions.push({ session: s, repoName: g.repo_name || "" });
 71→      });
 72→    });
 73→    (dashboardData.non_repo_groups || []).forEach(function (g) {
 74→      var name = g.cwd.split("/").filter(Boolean).pop() || g.cwd;
 75→      g.sessions.forEach(function (s) {
 76→        sessions.push({ session: s, repoName: name });
 77→      });
 78→    });
 79→    return sessions;
 80→  }
 81→
 82→  function fuzzyMatch(text, query) {
 83→    var tLower = text.toLowerCase();
 84→    var qLower = query.toLowerCase();
 85→    var qi = 0;
 86→    var indices = [];
 87→    for (var ti = 0; ti < tLower.length && qi < qLower.length; ti++) {
 88→      if (tLower[ti] === qLower[qi]) {
 89→        indices.push(ti);
 90→        qi++;
 91→      }
 92→    }
 93→    if (qi < qLower.length) return null;
 94→    // Score: prefer consecutive matches and matches at word boundaries
 95→    var score = 0;
 96→    for (var i = 0; i < indices.length; i++) {
 97→      if (i > 0 && indices[i] === indices[i - 1] + 1) score += 10;
 98→      if (indices[i] === 0 || text[indices[i] - 1] === " ") score += 5;
 99→    }
100→    return { indices: indices, score: score };
101→  }
102→
103→  function highlightMatches(text, indices) {
104→    if (!indices || indices.length === 0) return escapeHtml(text);
105→    var result = "";
106→    var idxSet = new Set(indices);
107→    var inMark = false;
108→    for (var i = 0; i < text.length; i++) {
109→      if (idxSet.has(i) && !inMark) {
110→        result += "<mark>";
111→        inMark = true;
112→      } else if (!idxSet.has(i) && inMark) {
113→        result += "</mark>";
114→        inMark = false;
115→      }
116→      result += escapeHtml(text[i]);
117→    }
118→    if (inMark) result += "</mark>";
119→    return result;
120→  }
121→
122→  function filterSessionByTime(session) {
123→    if (timeFilterDays === Infinity) return true;
124→    if (!session.last_active) return false;
125→    var cutoff = Date.now() - timeFilterDays * 24 * 60 * 60 * 1000;
126→    return new Date(session.last_active).getTime() >= cutoff;
127→  }
128→
129→  function filterGroupSessions(group) {
130→    return group.sessions.filter(filterSessionByTime);
131→  }
132→
133→  // --- Rendering ---
134→
135→  function renderSessionRow(session) {
136→    const cssCls = statusCssClass(session.status);
137→    const row = document.createElement("div");
138→    row.className = "session-row";
139→    row.innerHTML =
140→      '<div class="status-dot ' + cssCls + '"></div>' +
141→      '<div class="session-summary">' + escapeHtml(sessionLabel(session)) + "</div>" +
142→      '<span class="status-label ' + cssCls + '">' + escapeHtml(session.status) + "</span>" +
143→      '<span class="time-ago">' + timeAgo(session.last_active) + "</span>" +
144→      '<span class="source-badge ' + session.source + '">' + session.source + "</span>";
145→
146→    row.addEventListener("click", function () {
147→      launchSession(session, row);
148→    });
149→
150→    return row;
151→  }
152→
153→  // Octocat SVG icon for git repo groups
154→  var OCTOCAT_SVG = '<svg class="octocat-icon" viewBox="0 0 16 16" width="14" height="14" fill="currentColor">' +
155→    '<path d="M8 0C3.58 0 0 3.58 0 8c0 3.54 2.29 6.53 5.47 7.59.4.07.55-.17.55-.38 0-.19-.01-.82-.01-1.49' +
156→    '-2.01.37-2.53-.49-2.69-.94-.09-.23-.48-.94-.82-1.13-.28-.15-.68-.52-.01-.53.63-.01 1.08.58 1.23.82' +
157→    '.72 1.21 1.87.87 2.33.66.07-.52.28-.87.51-1.07-1.78-.2-3.64-.89-3.64-3.95 0-.87.31-1.59.82-2.15' +
158→    '-.08-.2-.36-1.02.08-2.12 0 0 .67-.21 2.2.82.64-.18 1.32-.27 2-.27.68 0 1.36.09 2 .27 1.53-1.04 2.2-.82' +
159→    ' 2.2-.82.44 1.1.16 1.92.08 2.12.51.56.82 1.27.82 2.15 0 3.07-1.87 3.75-3.65 3.95.29.25.54.73.54 1.48' +
160→    ' 0 1.07-.01 1.93-.01 2.2 0 .21.15.46.55.38A8.013 8.013 0 0016 8c0-4.42-3.58-8-8-8z"/></svg>';
161→
162→  function renderRepoGroup(group, filteredSessions) {
163→    if (filteredSessions.length === 0) return null;
164→
165→    var isExpanded = expandedRepos.has(group.repo_root);
166→    var container = document.createElement("div");
167→    container.className = "repo-group";
168→
169→    // Git meta string
170→    var metaParts = [];
171→    if (group.git_branch) metaParts.push(group.git_branch);
172→    if (group.git_dirty) metaParts.push('<span class="dirty">dirty</span>');
173→    if (group.unpushed_commits > 0) metaParts.push('<span class="unpushed">' + group.unpushed_commits + " unpushed</span>");
174→    if (!group.git_dirty && group.unpushed_commits === 0) metaParts.push("clean");
175→    metaParts.push(filteredSessions.length + " sessions");
176→
177→    var header = document.createElement("div");
178→    header.className = "repo-header";
179→    header.innerHTML =
180→      '<div class="repo-header-left">' +
181→      '<span class="repo-chevron ' + (isExpanded ? "expanded" : "") + '">\u25B6</span>' +
182→      OCTOCAT_SVG +
183→      '<span class="repo-name">' + escapeHtml(group.repo_name) + "</span>" +
184→      '<span class="repo-meta">(' + metaParts.join(", ") + ")</span>" +
185→      "</div>" +
186→      '<div class="repo-header-right">' +
187→      '<button class="btn-new-session" title="New Claude session in ' + escapeHtml(group.repo_root) + '">+</button>' +
188→      timeAgo(group.last_active) +
189→      "</div>";
190→
191→    var sessionList = document.createElement("div");
192→    sessionList.className = "session-list" + (isExpanded ? "" : " collapsed");
193→
194→    var visibleCount = INITIAL_VISIBLE;
195→    var showingAll = filteredSessions.length <= INITIAL_VISIBLE;
196→
197→    function renderVisibleSessions() {
198→      sessionList.innerHTML = "";
199→      var toShow = showingAll ? filteredSessions : filteredSessions.slice(0, visibleCount);
200→      toShow.forEach(function (session) {
201→        sessionList.appendChild(renderSessionRow(session));
202→      });
203→      if (!showingAll) {
204→        var moreBtn = document.createElement("div");
205→        moreBtn.className = "show-more-btn";
206→        moreBtn.textContent = "Show all " + filteredSessions.length + " sessions";
207→        moreBtn.addEventListener("click", function (e) {
208→          e.stopPropagation();
209→          showingAll = true;
210→          renderVisibleSessions();
211→          sessionList.style.maxHeight = sessionList.scrollHeight + "px";
212→        });
213→        sessionList.appendChild(moreBtn);
214→      }
215→    }
216→    renderVisibleSessions();
217→
218→    header.querySelector(".btn-new-session").addEventListener("click", function (e) {
219→      e.stopPropagation();
220→      openNewSession(group.repo_root);
221→    });
222→
223→    header.addEventListener("click", function () {
224→      if (expandedRepos.has(group.repo_root)) {
225→        expandedRepos.delete(group.repo_root);
226→        sessionList.classList.add("collapsed");
227→        header.querySelector(".repo-chevron").classList.remove("expanded");
228→      } else {
229→        expandedRepos.add(group.repo_root);
230→        sessionList.classList.remove("collapsed");
231→        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
232→        header.querySelector(".repo-chevron").classList.add("expanded");
233→      }
234→    });
235→
236→    // Set initial max-height for expanded groups
237→    if (isExpanded) {
238→      requestAnimationFrame(function () {
239→        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
240→      });
241→    }
242→
243→    container.appendChild(header);
244→    container.appendChild(sessionList);
245→    return container;
246→  }
247→
248→  function renderNonRepoGroup(group, filteredSessions) {
249→    if (filteredSessions.length === 0) return null;
250→
251→    var isExpanded = expandedRepos.has(group.cwd);
252→    var container = document.createElement("div");
253→    container.className = "repo-group";
254→
255→    // Use last path component as display name
256→    var displayName = group.cwd.split("/").filter(Boolean).pop() || group.cwd;
257→
258→    var header = document.createElement("div");
259→    header.className = "repo-header";
260→    header.innerHTML =
261→      '<div class="repo-header-left">' +
262→      '<span class="repo-chevron ' + (isExpanded ? "expanded" : "") + '">\u25B6</span>' +
263→      '<span class="repo-name">' + escapeHtml(displayName) + "</span>" +
264→      '<span class="repo-meta">(' + filteredSessions.length + " sessions)</span>" +
265→      "</div>" +
266→      '<div class="repo-header-right">' +
267→      '<button class="btn-new-session" title="New Claude session in ' + escapeHtml(group.cwd) + '">+</button>' +
268→      timeAgo(group.last_active) +
269→      "</div>";
270→
271→    var sessionList = document.createElement("div");
272→    sessionList.className = "session-list" + (isExpanded ? "" : " collapsed");
273→
274→    var showingAll = filteredSessions.length <= INITIAL_VISIBLE;
275→
276→    function renderVisibleSessions() {
277→      sessionList.innerHTML = "";
278→      var toShow = showingAll ? filteredSessions : filteredSessions.slice(0, INITIAL_VISIBLE);
279→      toShow.forEach(function (session) {
280→        sessionList.appendChild(renderSessionRow(session));
281→      });
282→      if (!showingAll) {
283→        var moreBtn = document.createElement("div");
284→        moreBtn.className = "show-more-btn";
285→        moreBtn.textContent = "Show all " + filteredSessions.length + " sessions";
286→        moreBtn.addEventListener("click", function (e) {
287→          e.stopPropagation();
288→          showingAll = true;
289→          renderVisibleSessions();
290→          sessionList.style.maxHeight = sessionList.scrollHeight + "px";
291→        });
292→        sessionList.appendChild(moreBtn);
293→      }
294→    }
295→    renderVisibleSessions();
296→
297→    header.querySelector(".btn-new-session").addEventListener("click", function (e) {
298→      e.stopPropagation();
299→      openNewSession(group.cwd);
300→    });
301→
302→    header.addEventListener("click", function () {
303→      if (expandedRepos.has(group.cwd)) {
304→        expandedRepos.delete(group.cwd);
305→        sessionList.classList.add("collapsed");
306→        header.querySelector(".repo-chevron").classList.remove("expanded");
307→      } else {
308→        expandedRepos.add(group.cwd);
309→        sessionList.classList.remove("collapsed");
310→        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
311→        header.querySelector(".repo-chevron").classList.add("expanded");
312→      }
313→    });
314→
315→    if (isExpanded) {
316→      requestAnimationFrame(function () {
317→        sessionList.style.maxHeight = sessionList.scrollHeight + "px";
318→      });
319→    }
320→
321→    container.appendChild(header);
322→    container.appendChild(sessionList);
323→    return container;
324→  }
325→
326→  function render() {
327→    if (!dashboardData) return;
328→
329→    $loading.classList.add("hidden");
330→
331→    var hasRepos = (dashboardData.repo_groups || []).length > 0;
332→    var hasNonRepos = (dashboardData.non_repo_groups || []).length > 0;
333→
334→    if (!hasRepos && !hasNonRepos) {
335→      $emptyState.classList.remove("hidden");
336→      $repoGroups.classList.add("hidden");
337→      $nonRepoGroups.classList.add("hidden");
338→      $chronoView.classList.add("hidden");
339→      return;
340→    }
341→
342→    $emptyState.classList.add("hidden");
343→    $chronoView.classList.add("hidden");
344→    $repoGroups.classList.remove("hidden");
345→    $nonRepoGroups.classList.add("hidden");
346→
347→    // Combine repo and non-repo groups into one list sorted by last_active
348→    var allGroups = [];
349→    (dashboardData.repo_groups || []).forEach(function (g) {
350→      allGroups.push({ type: "repo", group: g, last_active: g.last_active });
351→    });
352→    (dashboardData.non_repo_groups || []).forEach(function (g) {
353→      allGroups.push({ type: "non-repo", group: g, last_active: g.last_active });
354→    });
355→    allGroups.sort(function (a, b) {
356→      return new Date(b.last_active) - new Date(a.last_active);
357→    });
358→
359→    // Auto-expand the first group on initial render
360→    if (expandedRepos.size === 0 && allGroups.length > 0) {
361→      var firstGroup = allGroups[0];
362→      var expandKey = firstGroup.type === "repo" ? firstGroup.group.repo_root : firstGroup.group.cwd;
363→      expandedRepos.add(expandKey);
364→    }
365→
366→    $repoGroups.innerHTML = "";
367→    allGroups.forEach(function (entry) {
368→      var filtered = filterGroupSessions(entry.group);
369→      var el = entry.type === "repo"
370→        ? renderRepoGroup(entry.group, filtered)
371→        : renderNonRepoGroup(entry.group, filtered);
372→      if (el) $repoGroups.appendChild(el);
373→    });
374→  }
375→
376→  // --- API ---
377→
378→  function fetchSessions() {
379→    return fetch("/api/sessions")
380→      .then(function (res) { return res.json(); })
381→      .then(function (data) {
382→        dashboardData = data;
383→        lastScannedTime = data.last_scanned;
384→        updateSliderRange();
385→        render();
386→        updateLastScan();
387→      })
388→      .catch(function (err) {
389→        console.error("Failed to fetch sessions:", err);
390→      });
391→  }
392→
393→  function refreshSessions() {
394→    var days = parseInt($scanDays.value, 10) || 7;
395→    $btnRefresh.classList.add("spinning");
396→    $btnRefresh.textContent = "Refreshing...";
397→    return fetch("/api/refresh?scan_days=" + days)
398→      .then(function (res) { return res.json(); })
399→      .then(function (data) {
400→        dashboardData = data;
401→        lastScannedTime = data.last_scanned;
402→        updateSliderRange();
403→        render();
404→        updateLastScan();
405→      })
406→      .catch(function (err) {
407→        console.error("Failed to refresh:", err);
408→      })
409→      .finally(function () {
410→        $btnRefresh.classList.remove("spinning");
411→        $btnRefresh.textContent = "Refresh";
412→      });
413→  }
414→
415→  function launchSession(session, rowEl) {
416→    rowEl.classList.add("launched");
417→    setTimeout(function () { rowEl.classList.remove("launched"); }, 500);
418→    openTerminal(session);
419→  }
420→
421→  function openNewSession(cwd) {
422→    closeTerminal();
423→
424→    $terminalPanel.classList.remove("hidden");
425→    document.body.classList.add("terminal-open");
426→
427→    var term = new Terminal({
428→      fontFamily: '"JetBrains Mono", "SF Mono", monospace',
429→      fontSize: 13,
430→      theme: {
431→        background: "#111111",
432→        foreground: "#FAFAFA",
433→        cursor: "#FF4D00",
434→      },
435→      cursorBlink: true,
436→    });
437→
438→    var fitAddon = new FitAddon.FitAddon();
439→    term.loadAddon(fitAddon);
440→    term.loadAddon(new WebLinksAddon.WebLinksAddon());
441→
442→    term.open($terminalContainer);
443→    fitAddon.fit();
444→
445→    var params = new URLSearchParams({ mode: "new", cwd: cwd });
446→    var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
447→    var wsUrl = wsProtocol + "//" + location.host + "/ws/terminal?" + params.toString();
448→    var ws = new WebSocket(wsUrl);
449→
450→    ws.onopen = function () {
451→      ws.send(JSON.stringify({ type: "resize", cols: term.cols, rows: term.rows }));
452→      term.focus();
453→    };
454→
455→    ws.onmessage = function (evt) { term.write(evt.data); };
456→    ws.onclose = function () { term.write("\r\n\x1b[90m[session ended]\x1b[0m\r\n"); };
457→
458→    term.onData(function (data) {
459→      if (ws.readyState === WebSocket.OPEN) ws.send(data);
460→    });
461→
462→    term.onResize(function (size) {
463→      if (ws.readyState === WebSocket.OPEN) {
464→        ws.send(JSON.stringify({ type: "resize", cols: size.cols, rows: size.rows }));
465→      }
466→    });
467→
468→    window.addEventListener("resize", handleTerminalResize);
469→
470→    var displayName = cwd.split("/").filter(Boolean).pop() || cwd;
471→    $terminalTitle.textContent = "New session in " + displayName;
472→    activeTerminal = { term: term, ws: ws, fitAddon: fitAddon };
473→  }
474→
475→  // --- Terminal ---
476→
477→  var activeTerminal = null; // { term, ws, fitAddon }
478→  var $terminalPanel = document.getElementById("terminal-panel");
479→  var $terminalContainer = document.getElementById("terminal-container");
480→  var $terminalTitle = document.getElementById("terminal-title");
481→  var $terminalClose = document.getElementById("terminal-close");
482→
483→  function openTerminal(session) {
484→    closeTerminal();
485→
486→    $terminalPanel.classList.remove("hidden");
487→    document.body.classList.add("terminal-open");
488→
489→    var term = new Terminal({
490→      fontFamily: '"JetBrains Mono", "SF Mono", monospace',
491→      fontSize: 13,
492→      theme: {
493→        background: "#111111",
494→        foreground: "#FAFAFA",
495→        cursor: "#FF4D00",
496→      },
497→      cursorBlink: true,
498→    });
499→
500→    var fitAddon = new FitAddon.FitAddon();
501→    term.loadAddon(fitAddon);
502→    term.loadAddon(new WebLinksAddon.WebLinksAddon());
503→
504→    term.open($terminalContainer);
505→    fitAddon.fit();
506→
507→    var params = new URLSearchParams({
508→      source: session.source,
509→      session_id: session.id,
510→      cwd: session.cwd,
511→    });
512→    var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
513→    var wsUrl = wsProtocol + "//" + location.host + "/ws/terminal?" + params.toString();
514→    var ws = new WebSocket(wsUrl);
515→
516→    ws.onopen = function () {
517→      ws.send(JSON.stringify({
518→        type: "resize",
519→        cols: term.cols,
520→        rows: term.rows,
521→      }));
522→      term.focus();
523→    };
524→
525→    ws.onmessage = function (evt) {
526→      term.write(evt.data);
527→    };
528→
529→    ws.onclose = function () {
530→      term.write("\r\n\x1b[90m[session ended]\x1b[0m\r\n");
531→    };
532→
533→    term.onData(function (data) {
534→      if (ws.readyState === WebSocket.OPEN) {
535→        ws.send(data);
536→      }
537→    });
538→
539→    term.onResize(function (size) {
540→      if (ws.readyState === WebSocket.OPEN) {
541→        ws.send(JSON.stringify({
542→          type: "resize",
543→          cols: size.cols,
544→          rows: size.rows,
545→        }));
546→      }
547→    });
548→
549→    window.addEventListener("resize", handleTerminalResize);
550→
551→    $terminalTitle.textContent = sessionLabel(session);
552→    activeTerminal = { term: term, ws: ws, fitAddon: fitAddon };
553→  }
554→
555→  function handleTerminalResize() {
556→    if (activeTerminal) {
557→      activeTerminal.fitAddon.fit();
558→    }
559→  }
560→
561→  function closeTerminal() {
562→    if (!activeTerminal) return;
563→    activeTerminal.ws.close();
564→    activeTerminal.term.dispose();
565→    activeTerminal = null;
566→    $terminalPanel.classList.add("hidden");
567→    document.body.classList.remove("terminal-open");
568→    $terminalContainer.innerHTML = "";
569→    window.removeEventListener("resize", handleTerminalResize);
570→  }
571→
572→  $terminalClose.addEventListener("click", closeTerminal);
573→
574→  // --- Last scan timer ---
575→
576→  function updateLastScan() {
577→    if (lastScannedTime) {
578→      $lastScan.textContent = "Last scan: " + timeAgo(lastScannedTime);
579→    }
580→  }
581→
582→  // --- Time Slider ---
583→
584→  function computeMaxDays() {
585→    if (!dashboardData) return 60;
586→    var oldest = Infinity;
587→    var all = allSessions();
588→    all.forEach(function (entry) {
589→      if (entry.session.last_active) {
590→        var t = new Date(entry.session.last_active).getTime();
591→        if (t < oldest) oldest = t;
592→      }
593→    });
594→    if (oldest === Infinity) return 60;
595→    return Math.max(1, Math.ceil((Date.now() - oldest) / (24 * 60 * 60 * 1000)));
596→  }
597→
598→  function updateSliderRange() {
599→    var maxDays = computeMaxDays();
600→    $timeSlider.max = maxDays;
601→    $timeSlider.value = maxDays;
602→    timeFilterDays = Infinity;
603→    updateSliderLabel(maxDays, maxDays);
604→  }
605→
606→  function updateSliderLabel(val, max) {
607→    if (val >= max) {
608→      $timeSliderLabel.textContent = "All time";
609→    } else if (val === 1) {
610→      $timeSliderLabel.textContent = "Last 24h";
611→    } else {
612→      $timeSliderLabel.textContent = "Last " + val + "d";
613→    }
614→  }
615→
616→  $timeSlider.addEventListener("input", function () {
617→    var val = parseInt($timeSlider.value, 10);
618→    var max = parseInt($timeSlider.max, 10);
619→    if (val >= max) {
620→      timeFilterDays = Infinity;
621→    } else {
622→      timeFilterDays = val;
623→    }
624→    updateSliderLabel(val, max);
625→    render();
626→  });
627→
628→  // --- Search Overlay ---
629→
630→  var searchSelectedIdx = 0;
631→  var searchMatches = [];
632→
633→  function openSearch() {
634→    $searchOverlay.classList.remove("hidden");
635→    $searchInput.value = "";
636→    $searchResults.innerHTML = "";
637→    searchSelectedIdx = 0;
638→    searchMatches = [];
639→    $searchInput.focus();
640→  }
641→
642→  function closeSearch() {
643→    $searchOverlay.classList.add("hidden");
644→    $searchInput.value = "";
645→    $searchResults.innerHTML = "";
646→  }
647→
648→  function performSearch(query) {
649→    $searchResults.innerHTML = "";
650→    searchSelectedIdx = 0;
651→
652→    if (!query.trim()) {
653→      searchMatches = [];
654→      return;
655→    }
656→
657→    var all = allSessions();
658→    var scored = [];
659→    all.forEach(function (entry) {
660→      var label = sessionLabel(entry.session);
661→      var searchText = label + " " + entry.repoName + " " + (entry.session.status || "");
662→      var m = fuzzyMatch(searchText, query);
663→      if (m) {
664→        // Re-match just the label for highlighting
665→        var labelMatch = fuzzyMatch(label, query);
666→        scored.push({
667→          session: entry.session,
668→          repoName: entry.repoName,
669→          score: m.score,
670→          labelIndices: labelMatch ? labelMatch.indices : [],
671→        });
672→      }
673→    });
674→
675→    scored.sort(function (a, b) { return b.score - a.score; });
676→    searchMatches = scored.slice(0, 50);
677→
678→    if (searchMatches.length === 0) {
679→      $searchResults.innerHTML = '<div class="search-no-results">No matches</div>';
680→      return;
681→    }
682→
683→    searchMatches.forEach(function (match, idx) {
684→      var row = document.createElement("div");
685→      row.className = "search-result-row" + (idx === 0 ? " selected" : "");
686→      var cssCls = statusCssClass(match.session.status);
687→      row.innerHTML =
688→        '<div class="status-dot ' + cssCls + '"></div>' +
689→        '<div>' +
690→          '<div class="search-result-summary">' +
691→            highlightMatches(sessionLabel(match.session), match.labelIndices) +
692→          '</div>' +
693→          '<span class="search-result-repo">' + escapeHtml(match.repoName) + '</span>' +
694→        '</div>' +
695→        '<span class="status-label ' + cssCls + '">' +
696→          escapeHtml(match.session.status) + '</span>' +
697→        '<span class="time-ago">' + timeAgo(match.session.last_active) + '</span>';
698→
699→      row.addEventListener("click", function () {
700→        closeSearch();
701→        launchFromSearch(match.session);
702→      });
703→      $searchResults.appendChild(row);
704→    });
705→  }
706→
707→  function launchFromSearch(session) {
708→    openTerminal(session);
709→  }
710→
711→  function updateSearchSelection() {
712→    var rows = $searchResults.querySelectorAll(".search-result-row");
713→    rows.forEach(function (r, i) {
714→      r.classList.toggle("selected", i === searchSelectedIdx);
715→    });
716→    if (rows[searchSelectedIdx]) {
717→      rows[searchSelectedIdx].scrollIntoView({ block: "nearest" });
718→    }
719→  }
720→
721→  $searchInput.addEventListener("input", function () {
722→    performSearch($searchInput.value);
723→  });
724→
725→  $searchInput.addEventListener("keydown", function (e) {
726→    if (e.key === "Escape") {
727→      e.preventDefault();
728→      closeSearch();
729→    } else if (e.key === "ArrowDown") {
730→      e.preventDefault();
731→      if (searchMatches.length > 0) {
732→        searchSelectedIdx = Math.min(searchSelectedIdx + 1, searchMatches.length - 1);
733→        updateSearchSelection();
734→      }
735→    } else if (e.key === "ArrowUp") {
736→      e.preventDefault();
737→      if (searchMatches.length > 0) {
738→        searchSelectedIdx = Math.max(searchSelectedIdx - 1, 0);
739→        updateSearchSelection();
740→      }
741→    } else if (e.key === "Enter") {
742→      e.preventDefault();
743→      if (searchMatches.length > 0 && searchMatches[searchSelectedIdx]) {
744→        closeSearch();
745→        launchFromSearch(searchMatches[searchSelectedIdx].session);
746→      }
747→    }
748→  });
749→
750→  $searchOverlay.addEventListener("click", function (e) {
751→    if (e.target === $searchOverlay) closeSearch();
752→  });
753→
754→  document.addEventListener("keydown", function (e) {
755→    // Don't trigger if typing in an input, textarea, or terminal is focused
756→    if (e.target.tagName === "INPUT" || e.target.tagName === "TEXTAREA") return;
757→    if (activeTerminal) return;
758→    if (e.key === "/") {
759→      e.preventDefault();
760→      openSearch();
761→    }
762→  });
763→
764→  // --- Event listeners ---
765→
766→  $btnRefresh.addEventListener("click", refreshSessions);
767→
768→  // --- Init ---
769→
770→  fetchSessions();
771→})();
