545→<script>
546→  const slides = document.querySelectorAll('.slide');
547→  const dots = document.querySelectorAll('.nav-dots a');
548→  const inners = document.querySelectorAll('.slide-inner');
549→
550→  const observer = new IntersectionObserver((entries) => {
551→    entries.forEach(entry => {
552→      if (entry.isIntersecting) {
553→        entry.target.querySelector('.slide-inner').classList.add('visible');
554→        const idx = Array.from(slides).indexOf(entry.target);
555→        dots.forEach((d, i) => d.classList.toggle('active', i === idx));
556→      }
557→    });
558→  }, { threshold: 0.35 });
559→
560→  slides.forEach(s => observer.observe(s));
561→</script>
